int get_font40x80_index(char c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c == '-') return 10;
    if (c == ' ') return 11;
    if (c == '.') return 12;
    if (c == 'P') return 13;
    if (c == 'R') return 14;
    if (c == 'N') return 15;
    if (c == 'D') return 16;
    if (c == 'S') return 17;
    return 11; // fallback space
}
